"use client";

import { useMemo, useState } from "react";
import { useSearchParams } from "next/navigation";
import { sileo } from "sileo";

import {
  useCreateRegionMutation,
  useCreateZoneMutation,
  useDeleteRegionMutation,
  useDeleteZoneMutation,
  useRegionsQuery,
  useUpdateRegionMutation,
  useUpdateZoneMutation,
  useZonesQuery,
} from "@/hooks/use-base-data";
import type { Region, Zone } from "@/lib/api/base-data";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";

type SectionKey = "region" | "zone" | "woreda" | "kebele" | "religion";

function SectionPlaceholder({ title }: { title: string }) {
  return (
    <Card className="border-primary/10">
      <CardHeader>
        <CardTitle>{title}</CardTitle>
      </CardHeader>
      <CardContent className="text-sm text-muted-foreground">
        This base data module is prepared in navigation and can be implemented
        next.
      </CardContent>
    </Card>
  );
}

function RegionManager() {
  const [searchQuery, setSearchQuery] = useState("");
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [editingRegion, setEditingRegion] = useState<Region | null>(null);

  const regionsQuery = useRegionsQuery({ page: 1, pageSize: 20, searchQuery });
  const createMutation = useCreateRegionMutation();
  const updateMutation = useUpdateRegionMutation();
  const deleteMutation = useDeleteRegionMutation();

  const isSubmitting = createMutation.isPending || updateMutation.isPending;

  return (
    <div className="grid gap-4 lg:grid-cols-[360px_1fr]">
      <Card className="border-primary/10">
        <CardHeader>
          <CardTitle>{editingRegion ? "Update Region" : "Create Region"}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Input
            placeholder="Region name"
            value={name}
            onChange={(event) => setName(event.target.value)}
          />
          <textarea
            className="min-h-24 w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus:border-primary"
            placeholder="Description"
            value={description}
            onChange={(event) => setDescription(event.target.value)}
          />
          <div className="flex gap-2">
            <Button
              className="w-full bg-[#415A9F] text-white hover:bg-[#384d88]"
              disabled={isSubmitting}
              onClick={async () => {
                if (!name.trim()) {
                  sileo.warning({
                    title: "Missing name",
                    description: "Region name is required.",
                  });
                  return;
                }

                try {
                  if (editingRegion) {
                    const result = await updateMutation.mutateAsync({
                      id: editingRegion.id,
                      payload: { name: name.trim(), description: description.trim() },
                    });
                    sileo.success({ title: "Updated", description: result.message });
                  } else {
                    const result = await createMutation.mutateAsync({
                      name: name.trim(),
                      description: description.trim(),
                    });
                    sileo.success({ title: "Created", description: result.message });
                  }
                  setName("");
                  setDescription("");
                  setEditingRegion(null);
                } catch (error) {
                  sileo.error({
                    title: "Operation failed",
                    description:
                      error instanceof Error ? error.message : "Unexpected error",
                  });
                }
              }}
            >
              {editingRegion ? "Update Region" : "Create Region"}
            </Button>
            {editingRegion && (
              <Button
                variant="outline"
                onClick={() => {
                  setEditingRegion(null);
                  setName("");
                  setDescription("");
                }}
              >
                Cancel
              </Button>
            )}
          </div>
        </CardContent>
      </Card>

      <Card className="border-primary/10">
        <CardHeader>
          <CardTitle>Regions</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Input
            placeholder="Search region"
            value={searchQuery}
            onChange={(event) => setSearchQuery(event.target.value)}
          />
          <div className="max-h-[460px] space-y-2 overflow-auto pr-1">
            {regionsQuery.isLoading && (
              <p className="text-sm text-muted-foreground">Loading regions...</p>
            )}
            {regionsQuery.data?.regions?.map((region) => (
              <div
                key={region.id}
                className="rounded-lg border border-primary/10 bg-card px-3 py-2"
              >
                <div className="flex items-center justify-between gap-2">
                  <div>
                    <p className="font-semibold">{region.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {region.description || "---"}
                    </p>
                  </div>
                  <div className="flex gap-1">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => {
                        setEditingRegion(region);
                        setName(region.name);
                        setDescription(region.description || "");
                      }}
                    >
                      Edit
                    </Button>
                    <Button
                      size="sm"
                      variant="destructive"
                      onClick={async () => {
                        try {
                          const result = await deleteMutation.mutateAsync(region.id);
                          sileo.success({ title: "Deleted", description: result.message });
                        } catch (error) {
                          sileo.error({
                            title: "Delete failed",
                            description:
                              error instanceof Error
                                ? error.message
                                : "Unexpected error",
                          });
                        }
                      }}
                    >
                      Delete
                    </Button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

function ZoneManager() {
  const [searchQuery, setSearchQuery] = useState("");
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [regionId, setRegionId] = useState("");
  const [editingZone, setEditingZone] = useState<Zone | null>(null);

  const regionsQuery = useRegionsQuery({ page: 1, pageSize: 100 });
  const zonesQuery = useZonesQuery({ page: 1, pageSize: 20, searchQuery });

  const createMutation = useCreateZoneMutation();
  const updateMutation = useUpdateZoneMutation();
  const deleteMutation = useDeleteZoneMutation();

  const regionOptions = useMemo(
    () => regionsQuery.data?.regions ?? [],
    [regionsQuery.data?.regions]
  );

  return (
    <div className="grid gap-4 lg:grid-cols-[360px_1fr]">
      <Card className="border-primary/10">
        <CardHeader>
          <CardTitle>{editingZone ? "Update Zone" : "Create Zone"}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Input
            placeholder="Zone name"
            value={name}
            onChange={(event) => setName(event.target.value)}
          />
          <textarea
            className="min-h-24 w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus:border-primary"
            placeholder="Description"
            value={description}
            onChange={(event) => setDescription(event.target.value)}
          />
          <select
            className="h-10 w-full rounded-lg border border-input bg-background px-3 text-sm outline-none focus:border-primary"
            value={regionId}
            onChange={(event) => setRegionId(event.target.value)}
          >
            <option value="">Select region</option>
            {regionOptions.map((region) => (
              <option key={region.id} value={region.id}>
                {region.name}
              </option>
            ))}
          </select>

          <div className="flex gap-2">
            <Button
              className="w-full bg-[#415A9F] text-white hover:bg-[#384d88]"
              onClick={async () => {
                if (!name.trim() || !regionId) {
                  sileo.warning({
                    title: "Missing fields",
                    description: "Zone name and region are required.",
                  });
                  return;
                }

                try {
                  if (editingZone) {
                    const result = await updateMutation.mutateAsync({
                      id: editingZone.id,
                      payload: {
                        name: name.trim(),
                        description: description.trim(),
                        regionId,
                      },
                    });
                    sileo.success({ title: "Updated", description: result.message });
                  } else {
                    const result = await createMutation.mutateAsync({
                      name: name.trim(),
                      description: description.trim(),
                      regionId,
                    });
                    sileo.success({ title: "Created", description: result.message });
                  }
                  setName("");
                  setDescription("");
                  setRegionId("");
                  setEditingZone(null);
                } catch (error) {
                  sileo.error({
                    title: "Operation failed",
                    description:
                      error instanceof Error ? error.message : "Unexpected error",
                  });
                }
              }}
            >
              {editingZone ? "Update Zone" : "Create Zone"}
            </Button>
            {editingZone && (
              <Button
                variant="outline"
                onClick={() => {
                  setEditingZone(null);
                  setName("");
                  setDescription("");
                  setRegionId("");
                }}
              >
                Cancel
              </Button>
            )}
          </div>
        </CardContent>
      </Card>

      <Card className="border-primary/10">
        <CardHeader>
          <CardTitle>Zones</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Input
            placeholder="Search zone"
            value={searchQuery}
            onChange={(event) => setSearchQuery(event.target.value)}
          />
          <div className="max-h-[460px] space-y-2 overflow-auto pr-1">
            {zonesQuery.isLoading && (
              <p className="text-sm text-muted-foreground">Loading zones...</p>
            )}
            {zonesQuery.data?.zones?.map((zone) => (
              <div
                key={zone.id}
                className="rounded-lg border border-primary/10 bg-card px-3 py-2"
              >
                <div className="flex items-center justify-between gap-2">
                  <div>
                    <p className="font-semibold">{zone.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {zone.regionName} - {zone.description || "---"}
                    </p>
                  </div>
                  <div className="flex gap-1">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => {
                        setEditingZone(zone);
                        setName(zone.name);
                        setDescription(zone.description || "");
                        setRegionId(zone.regionId);
                      }}
                    >
                      Edit
                    </Button>
                    <Button
                      size="sm"
                      variant="destructive"
                      onClick={async () => {
                        try {
                          const result = await deleteMutation.mutateAsync(zone.id);
                          sileo.success({ title: "Deleted", description: result.message });
                        } catch (error) {
                          sileo.error({
                            title: "Delete failed",
                            description:
                              error instanceof Error
                                ? error.message
                                : "Unexpected error",
                          });
                        }
                      }}
                    >
                      Delete
                    </Button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

export function CommunityStructurePanel() {
  const searchParams = useSearchParams();
  const section = (searchParams.get("section") ?? "region") as SectionKey;

  if (section === "region") return <RegionManager />;
  if (section === "zone") return <ZoneManager />;
  if (section === "woreda") return <SectionPlaceholder title="Woreda" />;
  if (section === "kebele") return <SectionPlaceholder title="Kebele" />;
  return <SectionPlaceholder title="Religion" />;
}

